/**
 * Drizzle schema for ModelArena.
 *
 * Conventions:
 * - UUIDv4 primary keys, generated by the DB (`defaultRandom()`).
 * - Timestamps: `timestamp with time zone`, default `now()` on insert.
 *   `updatedAt` is intentionally NOT auto-updated by Drizzle — callers
 *   MUST set it explicitly on every UPDATE. Explicit is safer than a
 *   magic trigger.
 * - Immutable vote log: votes are never deleted or updated. Ratings are
 *   derived from votes and can be recomputed from scratch at any time.
 * - No global models catalog. `campaign_models` stores provider ids
 *   per-campaign. Cross-campaign aggregation depends on string equality
 *   of `provider_model_id`, which is why the UI must pick from a fixed
 *   catalog (src/lib/models.ts) and never free-type.
 *
 * Voting structure (tournament-per-prompt):
 *   Each (participant, prompt) plays one tournament with a 4-model
 *   bracket. Battles:
 *     b1: seed[0] vs seed[1]
 *     b2: seed[2] vs seed[3]
 *     b3: winner(b1) vs winner(b2)     — decides #1 / #2
 *     b4: loser(b1)  vs loser(b2)      — decides #3 / #4
 *     b5: rematch of b3's pair, IFF b3 was tie/both_bad — breaks the
 *         top-of-podium deadlock. Otherwise skipped.
 *   On a b1/b2 tie, a coin flip picks the advancer. The chosen
 *   generation is recorded in votes.advanced_generation_id so the
 *   result is auditable after the fact.
 *
 * Ratings: Bradley-Terry MM, iterated to convergence (≤ 0.0001) or 200
 * iters max. Standard errors from Fisher information, CI = rating ±
 * 1.96·SE. Display scale: rating = 1000 + 400·log10(strength/mean).
 * Sample-size thresholds (hide/preliminary/stable) live as code
 * constants, not schema.
 */
import {
  pgTable,
  pgEnum,
  text,
  uuid,
  timestamp,
  integer,
  numeric,
  jsonb,
  uniqueIndex,
  index,
} from 'drizzle-orm/pg-core';

export const campaignStatusEnum = pgEnum('campaign_status', [
  'draft',
  'active',
  'completed',
]);

export const voteWinnerEnum = pgEnum('vote_winner', [
  'A',
  'B',
  'tie',
  'both_bad',
]);

export const tournamentStatusEnum = pgEnum('tournament_status', [
  'in_progress',
  'complete',
]);

export const bracketPositionEnum = pgEnum('bracket_position', [
  'b1',
  'b2',
  'b3',
  'b4',
  'b5',
]);

export const campaigns = pgTable('campaigns', {
  id: uuid('id').primaryKey().defaultRandom(),
  shareSlug: text('share_slug').notNull().unique(),
  name: text('name').notNull(),
  description: text('description').notNull().default(''),
  categories: text('categories').array().notNull().default([]),
  status: campaignStatusEnum('status').notNull().default('draft'),
  createdAt: timestamp('created_at', { withTimezone: true })
    .notNull()
    .defaultNow(),
  updatedAt: timestamp('updated_at', { withTimezone: true })
    .notNull()
    .defaultNow(),
  closedAt: timestamp('closed_at', { withTimezone: true }),
});

export const prompts = pgTable(
  'prompts',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    orderIndex: integer('order_index').notNull(),
    text: text('text').notNull(),
    context: text('context'),
    categoryTags: text('category_tags').array().notNull().default([]),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [index('prompts_campaign_order').on(t.campaignId, t.orderIndex)],
);

export const campaignModels = pgTable(
  'campaign_models',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    providerModelId: text('provider_model_id').notNull(),
    displayName: text('display_name').notNull(),
    params: jsonb('params').notNull().default({}),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_campaign_model').on(t.campaignId, t.providerModelId),
  ],
);

/**
 * One row per (prompt, campaign_model). Retry overwrites (UPSERT).
 * `output` is null until the generation completes; `error` is non-null
 * if it failed. Both-null means queued but not yet started.
 */
export const generations = pgTable(
  'generations',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    output: text('output'),
    tokensIn: integer('tokens_in'),
    tokensOut: integer('tokens_out'),
    latencyMs: integer('latency_ms'),
    costUsd: numeric('cost_usd', { precision: 12, scale: 8 }),
    providerResponseId: text('provider_response_id'),
    error: text('error'),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    completedAt: timestamp('completed_at', { withTimezone: true }),
  },
  (t) => [uniqueIndex('uniq_prompt_model').on(t.promptId, t.campaignModelId)],
);

/**
 * One row per (cookie, campaign). Same cookie visiting two campaigns
 * creates two participant rows — that's intentional; group-agreement
 * metrics are computed within a campaign.
 */
export const participants = pgTable(
  'participants',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    cookieId: uuid('cookie_id').notNull(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    email: text('email'),
    startedAt: timestamp('started_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    finishedAt: timestamp('finished_at', { withTimezone: true }),
  },
  (t) => [uniqueIndex('uniq_cookie_campaign').on(t.cookieId, t.campaignId)],
);

/**
 * One tournament per (participant, prompt). `seedModelIds` is an ordered
 * array of exactly 4 campaign_model ids defining the bracket:
 *   b1: seed[0] vs seed[1]
 *   b2: seed[2] vs seed[3]
 *   b3/b4/b5: determined by outcomes.
 *
 * When the campaign has exactly 4 models, all participants get the same
 * seed (ordered by campaign_models.created_at). When >4, each tournament
 * samples 4 independently — coverage > explainability. When <4 models,
 * activation is rejected.
 *
 * `status` flips to 'complete' once the required battles for this
 * tournament are recorded. `completedAt` is set at the same time.
 */
export const tournaments = pgTable(
  'tournaments',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    seedModelIds: uuid('seed_model_ids').array().notNull(),
    status: tournamentStatusEnum('status').notNull().default('in_progress'),
    startedAt: timestamp('started_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    completedAt: timestamp('completed_at', { withTimezone: true }),
  },
  (t) => [
    uniqueIndex('uniq_tournament_participant_prompt').on(
      t.participantId,
      t.promptId,
    ),
  ],
);

/**
 * Immutable. Dedup is on (tournament_id, bracket_position): no
 * participant can vote at the same bracket position twice within a
 * tournament.
 *
 * `advancedGenerationId` is set for b1 and b2 rows to record the
 * generation that moved on to b3:
 *   - winner='A' → advancedGenerationId = generationAId
 *   - winner='B' → advancedGenerationId = generationBId
 *   - winner='tie'/'both_bad' → randomly chosen by the handler; stored
 *     verbatim so the result is auditable
 * Null at b3/b4/b5 (no downstream propagation).
 *
 * `sessionId` is a diagnostic tag — new UUID per /vote/:slug visit.
 * Useful for "how many battles did this participant do in one sitting."
 */
export const votes = pgTable(
  'votes',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    tournamentId: uuid('tournament_id')
      .notNull()
      .references(() => tournaments.id, { onDelete: 'cascade' }),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    sessionId: uuid('session_id').notNull(),
    bracketPosition: bracketPositionEnum('bracket_position').notNull(),
    generationAId: uuid('generation_a_id')
      .notNull()
      .references(() => generations.id),
    generationBId: uuid('generation_b_id')
      .notNull()
      .references(() => generations.id),
    winner: voteWinnerEnum('winner').notNull(),
    advancedGenerationId: uuid('advanced_generation_id').references(
      () => generations.id,
    ),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_vote_tournament_position').on(
      t.tournamentId,
      t.bracketPosition,
    ),
    index('votes_campaign').on(t.campaignId),
    index('votes_prompt').on(t.promptId),
    index('votes_participant').on(t.participantId),
  ],
);

/**
 * Denormalized per-category rating cache. Only GLOBAL ratings — personal
 * ratings are computed transiently on the results page.
 *
 * Category sentinel 'overall' represents the campaign aggregate; other
 * values are user-defined category tags.
 *
 * Columns:
 *   - `rating`      Display scale (1000-centered). Null until first
 *                   compute pass.
 *   - `seRating`    Standard error on the rating scale, from Fisher
 *                   information. Null until first compute.
 *   - `ciLow/High`  rating ± 1.96·seRating. Stored for read convenience.
 *   - `btStrength`  Raw B-T strength post-convergence, post-normalization.
 *                   Stored for debugging; not shown in UI.
 *   - `gameCount`   Number of comparisons contributing to this row.
 */
export const ratings = pgTable(
  'ratings',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    category: text('category').notNull().default('overall'),
    rating: integer('rating').notNull().default(1000),
    seRating: numeric('se_rating', { precision: 10, scale: 6 }),
    ciLow: integer('ci_low'),
    ciHigh: integer('ci_high'),
    btStrength: numeric('bt_strength', { precision: 12, scale: 8 }),
    gameCount: integer('game_count').notNull().default(0),
    computedAt: timestamp('computed_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_rating').on(
      t.campaignId,
      t.campaignModelId,
      t.category,
    ),
  ],
);

// Types exported for use in API handlers and helpers.
export type Campaign = typeof campaigns.$inferSelect;
export type NewCampaign = typeof campaigns.$inferInsert;
export type Prompt = typeof prompts.$inferSelect;
export type NewPrompt = typeof prompts.$inferInsert;
export type CampaignModel = typeof campaignModels.$inferSelect;
export type NewCampaignModel = typeof campaignModels.$inferInsert;
export type Generation = typeof generations.$inferSelect;
export type NewGeneration = typeof generations.$inferInsert;
export type Participant = typeof participants.$inferSelect;
export type NewParticipant = typeof participants.$inferInsert;
export type Tournament = typeof tournaments.$inferSelect;
export type NewTournament = typeof tournaments.$inferInsert;
export type Vote = typeof votes.$inferSelect;
export type NewVote = typeof votes.$inferInsert;
export type Rating = typeof ratings.$inferSelect;
export type NewRating = typeof ratings.$inferInsert;
